class Solution:
    def findMaximumNumber(self, k: int, x: int) -> int:
        def price(num: int) -> int:
            """Calculate the price of a number based on set bits at positions divisible by x."""
            res = 0
            pos = 1
            while (1 << (pos - 1)) <= num:
                if pos % x == 0:
                    res += (num >> (pos - 1)) & 1
                pos += 1
            return res

        def total_price(max_num: int) -> int:
            """Calculate the total price from 1 to max_num."""
            total = 0
            for num in range(1, max_num + 1):
                total += price(num)
                if total > k:
                    return total
            return total

        # Binary search
        low = 1
        high = 10**18  # A safe upper bound
        answer = 0

        while low <= high:
            mid = (low + high) // 2
            total = total_price(mid)
            if total <= k:
                answer = mid
                low = mid + 1
            else:
                high = mid - 1

        return answer
